    var goalText = String(h.goal || "").toLowerCase();
    var desiredOutputsText = String(h.desiredOutputs || "").toLowerCase();
    var resolvedBriefFactors =
      h.resolvedBriefFactors && typeof h.resolvedBriefFactors === "object"
