          syncWorkflowRunCapturedOutputToState(currentLi);
          var sid = String(currentLi.getAttribute("data-step-id") || "").trim();
          if (sid) {
            state.workflowRunStepCompleted[sid] = true;
          }
          updateRunStepOutputStatus(currentLi);
